sys_script_include.script:
function AppSanityPostInstall(vApp)
{
	function Log(vValue)
	{
		x_snc_devtools.Log('AppSanityPostInstall: '+RenderValue(vValue));
	}

	var grApp = GetAppRecord(vApp);
	if (grApp == false)
	{
		Log('Error: App not found!');
		return false;	
	}

	var	strAppSysId = GetStringValue(grApp.sys_id);

	Log('Deleting auto-generated sys_wizard_answer records');
	var grRecords = new GlideRecord('sys_wizard_answer');
	grRecords.addQuery('sys_scope','=',strAppSysId);
	grRecords.addQuery('table','=','');
	grRecords.query();
	while (grRecords.next())
	{
		Log('Deleting record: '+ RenderRecordSummary(grRecords));
		GlideRecordDelete(grRecords,true);
	}

	Log('Re-activating agentic usecase trigger records');
    var grRecords = new GlideRecord("sn_aia_trigger_agent_usecase_m2m");
	grRecords.addQuery('sys_scope','=',strAppSysId);
	grRecords.addActiveQuery();
	grRecords.query();
    while (grRecords.next() == true)
	{
		// Deactivate the trigger
        grRecords.active = false;
        GlideRecordUpdate(grRecords);

		// Reactivate the trigger to make it work
        grRecords.active = true;
        GlideRecordUpdate(grRecords);
    }

	Log('Completed!');

	return true;
}
